const allowed = new Set(['OFFLINE', 'VALIDATE', 'DRY_RUN', 'LIVE']);
const requested = $json.execution_mode;
const executionMode = typeof requested === 'string' && allowed.has(requested) ? requested : 'OFFLINE';
return [{json:{
  ...$json,
  execution_mode: executionMode,
  dry_run: $json.dry_run === false ? false : true,
  founder_write_approved: $json.founder_write_approved === true,
  credentials_configured: $json.credentials_configured === true
}}];

const mode = $json.execution_mode === 'VALIDATE' ? 'VALIDATE' : 'OFFLINE';
return [{json:{
  status: mode === 'VALIDATE' ? 'validate_local_only' : 'offline_local_only',
  execution_mode: mode,
  network_performed: false,
  write_performed: false,
  local_validation_required: true,
  validation_scope: ['manifest', 'registry', 'schema', 'workflows', 'secrets', 'execution_mode'],
  validation_command: 'python3 scripts/validate_manifest.py'
}}];

const cfg = $('Validate Repository Configuration').first().json;
const payload = $json;
if (!payload || payload.type !== 'file' || payload.path !== cfg.manifest_path) {
  throw new Error('Manifest repository response identity mismatch.');
}
if (payload.encoding !== 'base64' || typeof payload.content !== 'string' || !payload.content.trim()) {
  throw new Error('Manifest repository response is empty or malformed.');
}
let decoded;
let manifest;
try {
  decoded = Buffer.from(payload.content.replace(/\n/g, ''), 'base64').toString('utf8');
  if (!decoded.trim()) throw new Error('empty decoded manifest');
  manifest = JSON.parse(decoded);
} catch (error) {
  throw new Error(`Manifest decode failed: ${error.message}`);
}
if (!manifest.atlas || !Array.isArray(manifest.domains) || !Array.isArray(manifest.documents)) {
  throw new Error('Manifest structure is invalid.');
}
const safePath = (value) => {
  if (typeof value !== 'string' || !value || value.startsWith('/') || value.includes('\\\\')) return false;
  const parts = value.split('/');
  return !parts.some(part => !part || part === '.' || part === '..');
};
const ids = new Set();
const paths = new Set();
for (const document of manifest.documents) {
  if (!document || typeof document.id !== 'string' || !/^[A-Z]{2,3}-\d{3}$/.test(document.id)) {
    throw new Error('Manifest contains an invalid document identity.');
  }
  if (ids.has(document.id)) throw new Error(`Duplicate document ID: ${document.id}`);
  if (!safePath(document.path)) throw new Error(`Unsafe document path: ${document.id}`);
  if (paths.has(document.path)) throw new Error(`Duplicate document path: ${document.path}`);
  ids.add(document.id);
  paths.add(document.path);
}
for (const document of manifest.documents) {
  const dependencies = document.dependencies || [];
  if (!Array.isArray(dependencies) || new Set(dependencies).size !== dependencies.length) {
    throw new Error(`Duplicate or malformed dependencies: ${document.id}`);
  }
  for (const dependency of dependencies) {
    if (!ids.has(dependency)) throw new Error(`Unknown dependency ${dependency} for ${document.id}`);
  }
}
return [{json:{...cfg, manifest, manifest_sha: payload.sha || null}}];

const cfg = $json;
const documents = cfg.manifest.documents || [];
const index = {};
for (const document of documents) {
  index[document.id] = {
    id: document.id,
    title: document.title,
    domain: document.domain,
    path: document.path,
    status: document.status,
    owner: document.owner,
    minimum_words: document.minimum_words,
    dependencies: document.dependencies || [],
    required_sections: document.required_sections || []
  };
}
const pending = documents.filter(document => document.status === 'pending');
if (!pending.length) return [];
return pending.map(document => ({json: {
  ...document,
  registry_entry: index[document.id],
  pipeline: {
    github_owner: cfg.github_owner,
    github_repo: cfg.github_repo,
    branch: cfg.branch,
    expected_repository: cfg.expected_repository,
    expected_branch: cfg.expected_branch,
    manifest_path: cfg.manifest_path,
    schema_path: cfg.schema_path,
    template_path: cfg.template_path,
    required_governance_paths: cfg.required_governance_paths,
    manifest_version: cfg.manifest.atlas.version,
    manifest_sha: cfg.manifest_sha,
    document_index: index,
    execution_mode: cfg.execution_mode,
    dry_run: cfg.dry_run,
    founder_write_approved: cfg.founder_write_approved,
    credentials_configured: cfg.credentials_configured,
    generator_workflow_id: cfg.generator_workflow_id
  }
}}));

const items = $input.all();
return [{json:{
  completed_at: new Date().toISOString(),
  processed_documents: items.length,
  results: items.map(i => ({id:i.json.document_id || i.json.id, status:i.json.status, validation:i.json.validation_status, write_performed:i.json.write_performed === true}))
}}];

const cfg = $json;
const requiredStrings = [
  'github_owner', 'github_repo', 'branch', 'expected_repository',
  'expected_branch', 'manifest_path', 'schema_path', 'template_path'
];
for (const key of requiredStrings) {
  const value = cfg[key];
  if (typeof value !== 'string' || !value.trim() || value.includes('CONFIGURE_')) {
    throw new Error(`Repository configuration invalid: ${key}`);
  }
}
const safePath = (value) => {
  if (typeof value !== 'string' || !value || value.startsWith('/') || value.includes('\\\\')) return false;
  const parts = value.split('/');
  return !parts.some(part => !part || part === '.' || part === '..');
};
for (const key of ['manifest_path', 'schema_path', 'template_path']) {
  if (!safePath(cfg[key])) throw new Error(`Unsafe repository path: ${key}`);
}
if (cfg.manifest_path !== 'n8n/config/ATLAS_MASTER_MANIFEST.json') {
  throw new Error('Manifest path mismatch.');
}
if (cfg.schema_path !== 'atlas/DOCUMENT_OUTPUT_SCHEMA.json' || cfg.template_path !== 'atlas/DOCUMENT_TEMPLATE.md') {
  throw new Error('Canonical schema or template path mismatch.');
}
const actualRepository = `${cfg.github_owner}/${cfg.github_repo}`;
if (cfg.expected_repository !== actualRepository) throw new Error('Repository identity mismatch.');
if (cfg.expected_branch !== cfg.branch) throw new Error('Branch identity mismatch.');
const governance = cfg.required_governance_paths;
if (!Array.isArray(governance) || !governance.length || new Set(governance).size !== governance.length) {
  throw new Error('Required governance path configuration is invalid.');
}
for (const path of governance) {
  if (!safePath(path)) throw new Error(`Unsafe governance path: ${path}`);
}
for (const required of ['PROJECT_BIBLE.md', 'AGENTS.md']) {
  if (!governance.includes(required)) throw new Error(`Missing mandatory governance path: ${required}`);
}
return [{json: cfg}];
